import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles.js';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory,
  nextIslandByArrow,
  areAdjacent,
} from './utils/hashiLogic.js';

const GRID = 40;
const W = 800;
const H = 600;

function px(n) {
  return n * GRID;
}

function midpoint(a, b) {
  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function islandAt(islands, x, y) {
  return islands.find(i => i.x === x && i.y === y) || null;
}

function bridgeUnderPointer(islands, bridges, svgPoint, tolerancePx = 8) {
  // svgPoint in px coords.
  // For each bridge segment, compute distance to segment (axis-aligned).
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = { x: px(x1), y: px(y1) };
    const b = { x: px(x2), y: px(y2) };

    if (a.x === b.x) {
      const x = a.x;
      const yMin = Math.min(a.y, b.y);
      const yMax = Math.max(a.y, b.y);
      if (Math.abs(svgPoint.x - x) <= tolerancePx && svgPoint.y >= yMin && svgPoint.y <= yMax) {
        return { key, count };
      }
    } else if (a.y === b.y) {
      const y = a.y;
      const xMin = Math.min(a.x, b.x);
      const xMax = Math.max(a.x, b.x);
      if (Math.abs(svgPoint.y - y) <= tolerancePx && svgPoint.x >= xMin && svgPoint.x <= xMax) {
        return { key, count };
      }
    }
  }
  return null;
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id ?? null);
  const [mode, setMode] = useState('idle'); // idle | choosingTarget
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    // puzzle change: fully reset
    setBridges(new Map());
    setSelectedIslandId(null);
    setCursorIslandId(puzzles[puzzleIndex].islands[0]?.id ?? null);
    setMode('idle');
    setError(null);
  }, [puzzleIndex]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  const selectedIsland = useMemo(
    () => islands.find(i => i.id === selectedIslandId) || null,
    [islands, selectedIslandId]
  );

  const cursorIsland = useMemo(
    () => islands.find(i => i.id === cursorIslandId) || islands[0] || null,
    [islands, cursorIslandId]
  );

  function clearErrorOnValidMove(valid) {
    if (valid) setError(null);
  }

  function applyToggleBridge(from, to, direction = +1) {
    // direction +1 cycles upward; -1 cycles downward
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) || 0;
    const delta = direction;
    const { valid, error: err } = canAddBridge(islands, bridges, from, to, delta);
    if (!valid) {
      setError(err);
      return;
    }

    const next = current + delta;
    const nextClamped = ((next % 3) + 3) % 3; // handles -1 case

    // If we were allowed to decrement below 0, normalize here
    const newMap = new Map(bridges);
    if (nextClamped === 0) newMap.delete(key);
    else newMap.set(key, nextClamped);
    setBridges(newMap);
    clearErrorOnValidMove(true);
  }

  function cycleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const current = bridges.get(key) || 0;
    const target = (current + 1) % 3;

    // Determine intended delta (+1, +1, or -2 in terms of cycling 2->0)
    // We'll apply step-by-step to validate constraints properly.
    if (target === current) return;

    if (current === 0 && target === 1) {
      const res = canAddBridge(islands, bridges, from, to, +1);
      if (!res.valid) return setError(res.error);
      const m = new Map(bridges);
      m.set(key, 1);
      setBridges(m);
      return clearErrorOnValidMove(true);
    }
    if (current === 1 && target === 2) {
      const res = canAddBridge(islands, bridges, from, to, +1);
      if (!res.valid) return setError(res.error);
      const m = new Map(bridges);
      m.set(key, 2);
      setBridges(m);
      return clearErrorOnValidMove(true);
    }
    if (current === 2 && target === 0) {
      const m = new Map(bridges);
      m.delete(key);
      setBridges(m);
      return clearErrorOnValidMove(true);
    }
  }

  function handleIslandClick(isl) {
    if (!selectedIslandId) {
      setSelectedIslandId(isl.id);
      setCursorIslandId(isl.id);
      setMode('idle');
      return;
    }
    if (selectedIslandId === isl.id) {
      // reselect same island
      setCursorIslandId(isl.id);
      return;
    }
    const from = islands.find(i => i.id === selectedIslandId);
    const to = isl;
    // second click toggles
    const resAdj = areAdjacent(islands, from, to);
    if (!resAdj) {
      setError('Cannot connect non-adjacent islands');
      setSelectedIslandId(null);
      setMode('idle');
      return;
    }
    cycleBridge(from, to);
    setSelectedIslandId(null);
    setMode('idle');
  }

  function svgPointFromEvent(evt) {
    const svg = svgRef.current;
    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    const ctm = svg.getScreenCTM();
    if (!ctm) return { x: 0, y: 0 };
    const p = pt.matrixTransform(ctm.inverse());
    return { x: p.x, y: p.y };
  }

  function handleContextOrCtrlClickBridge(evt) {
    const isCtrl = evt.ctrlKey;
    const isRight = evt.type === 'contextmenu' || evt.button === 2;
    if (!isCtrl && !isRight) return;
    evt.preventDefault();

    const p = svgPointFromEvent(evt);
    const hit = bridgeUnderPointer(islands, bridges, p);
    if (!hit) return;

    const { x1, y1, x2, y2 } = parseKey(hit.key);
    const from = islandAt(islands, x1, y1);
    const to = islandAt(islands, x2, y2);
    if (!from || !to) return;

    // toggle (cycle) bridge count by +1: none->1->2->none
    cycleBridge(from, to);
  }

  useEffect(() => {
    function onKeyDown(e) {
      if (!cursorIsland) return;

      if (e.key === 'Escape') {
        setSelectedIslandId(null);
        setMode('idle');
        return;
      }

      if (e.key.startsWith('Arrow')) {
        e.preventDefault();
        const next = nextIslandByArrow(islands, cursorIsland, e.key);
        if (next) {
          setCursorIslandId(next.id);
        }
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (!selectedIslandId) {
          setSelectedIslandId(cursorIsland.id);
          setMode('choosingTarget');
          return;
        }
        // selected exists; toggling bridge between selected and cursor if different
        const from = islands.find(i => i.id === selectedIslandId);
        const to = cursorIsland;
        if (!from || !to || from.id === to.id) {
          setSelectedIslandId(null);
          setMode('idle');
          return;
        }
        if (!areAdjacent(islands, from, to)) {
          setError('Cannot connect non-adjacent islands');
          setSelectedIslandId(null);
          setMode('idle');
          return;
        }
        cycleBridge(from, to);
        setSelectedIslandId(null);
        setMode('idle');
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorIsland, islands, selectedIslandId, bridges]);

  function reset() {
    setBridges(new Map());
    setSelectedIslandId(null);
    setMode('idle');
    setError(null);
  }

  // Render bridges
  const bridgeLines = [];
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = { x: px(x1), y: px(y1) };
    const b = { x: px(x2), y: px(y2) };

    const isH = a.y === b.y;
    const off = 5;
    const stroke = '#00ff66';
    const width = 3;

    if (count === 1) {
      bridgeLines.push(
        <line
          key={key}
          x1={a.x}
          y1={a.y}
          x2={b.x}
          y2={b.y}
          stroke={stroke}
          strokeWidth={width}
          shapeRendering="crispEdges"
        />
      );
    } else if (count === 2) {
      if (isH) {
        bridgeLines.push(
          <g key={key}>
            <line x1={a.x} y1={a.y - off} x2={b.x} y2={b.y - off} stroke={stroke} strokeWidth={width} shapeRendering="crispEdges" />
            <line x1={a.x} y1={a.y + off} x2={b.x} y2={b.y + off} stroke={stroke} strokeWidth={width} shapeRendering="crispEdges" />
          </g>
        );
      } else {
        bridgeLines.push(
          <g key={key}>
            <line x1={a.x - off} y1={a.y} x2={b.x - off} y2={b.y} stroke={stroke} strokeWidth={width} shapeRendering="crispEdges" />
            <line x1={a.x + off} y1={a.y} x2={b.x + off} y2={b.y} stroke={stroke} strokeWidth={width} shapeRendering="crispEdges" />
          </g>
        );
      }
    }
  }

  // Cursor marker (non-circle)
  const cursorMarker = cursorIsland ? (
    <rect
      x={px(cursorIsland.x) - 18}
      y={px(cursorIsland.y) - 18}
      width={36}
      height={36}
      fill="none"
      stroke={mode === 'choosingTarget' || selectedIslandId ? '#7CFFAA' : '#00aa44'}
      strokeWidth={3}
      vectorEffect="non-scaling-stroke"
    />
  ) : null;

  return (
    <>
      <div className="controls">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          >
            {puzzles.map((p, idx) => (
              <option key={p.label} value={idx}>{p.label}</option>
            ))}
          </select>
        </label>
        <button onClick={reset}>Reset</button>
        <div style={{ color: '#00aa44' }}>
          Click: select island then another. Right-click/Ctrl+click on a bridge toggles it. Arrow keys + Enter.
        </div>
      </div>

      {victory ? <div className="victory-banner">SOLVED!</div> : null}
      {!victory && error ? <div className="error-message">{error}</div> : null}

      <svg
        ref={svgRef}
        width={W}
        height={H}
        style={{ position: 'fixed', left: 0, top: 0 }}
        onContextMenu={handleContextOrCtrlClickBridge}
        onMouseDown={(e) => {
          if (e.ctrlKey) handleContextOrCtrlClickBridge(e);
        }}
      >
        <rect x={0} y={0} width={W} height={H} fill="#000" />

        {bridgeLines}
        {cursorMarker}

        {islands.map((isl) => {
          const c = counts.get(isl.id) || 0;
          const satisfied = c === isl.value;
          const over = c > isl.value;
          const stroke = over ? '#ff4466' : (satisfied ? '#7CFFAA' : '#00ff66');
          const fill = '#000';
          const r = 16;

          return (
            <g
              key={isl.id}
              transform={`translate(${px(isl.x)},${px(isl.y)})`}
              onMouseDown={(e) => {
                e.preventDefault();
                handleIslandClick(isl);
              }}
              style={{ cursor: 'pointer' }}
            >
              <circle cx={0} cy={0} r={r} fill={fill} stroke={stroke} strokeWidth={3} />
              <text
                x={0}
                y={5}
                textAnchor="middle"
                fontSize="16"
                fill={stroke}
              >
                {isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </>
  );
}
