const ERR_NON_ADJ = 'Cannot connect non-adjacent islands';
const ERR_MAX2 = 'Max 2 bridges per pair';
const ERR_EXCEED = 'Island would exceed its number';
const ERR_CROSS = 'Bridges would cross';

export function canonicalBridgeKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  if (a.x < b.x || (a.x === b.x && a.y <= b.y)) {
    return `${a.x},${a.y},${b.x},${b.y}`;
  }
  return `${b.x},${b.y},${a.x},${a.y}`;
}

function isSamePoint(p, q) {
  return p.x === q.x && p.y === q.y;
}

function getSegments(islands, bridges) {
  // return list of segments in grid units: { from:{x,y}, to:{x,y}, key }
  const segs = [];
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    segs.push({ from: { x: x1, y: y1 }, to: { x: x2, y: y2 }, key, count });
  }
  return segs;
}

function between(v, a, b) {
  const lo = Math.min(a, b);
  const hi = Math.max(a, b);
  return v > lo && v < hi;
}

function segmentsCross(s1, s2) {
  // Only consider proper crossings (interior intersection). Shared endpoints are allowed.
  const a = s1.from, b = s1.to;
  const c = s2.from, d = s2.to;
  const s1H = a.y === b.y;
  const s2H = c.y === d.y;
  const s1V = a.x === b.x;
  const s2V = c.x === d.x;

  if ((s1H && s2H) || (s1V && s2V)) return false;

  let h, v;
  if (s1H && s2V) {
    h = s1; v = s2;
  } else if (s1V && s2H) {
    h = s2; v = s1;
  } else {
    return false;
  }

  const hy = h.from.y;
  const vx = v.from.x;

  // Check intersection point is strictly inside both segments
  if (!between(vx, h.from.x, h.to.x)) return false;
  if (!between(hy, v.from.y, v.to.y)) return false;

  // Exclude if intersection is at an endpoint (should already be excluded by between)
  const p = { x: vx, y: hy };
  if (isSamePoint(p, h.from) || isSamePoint(p, h.to) || isSamePoint(p, v.from) || isSamePoint(p, v.to)) {
    return false;
  }
  return true;
}

function crossesAny(existingBridges, candidateSeg, ignoreKey = null) {
  const segs = getSegments(null, existingBridges);
  for (const s of segs) {
    if (ignoreKey && s.key === ignoreKey) continue;
    if (segmentsCross(s, candidateSeg)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  const byCoord = new Map(islands.map(i => [`${i.x},${i.y}`, i]));
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const i1 = byCoord.get(`${x1},${y1}`);
    const i2 = byCoord.get(`${x2},${y2}`);
    if (!i1 || !i2) continue;
    counts.set(i1.id, (counts.get(i1.id) || 0) + count);
    counts.set(i2.id, (counts.get(i2.id) || 0) + count);
  }
  return counts;
}

function nearestIslandInDirection(islandsByCoord, from, dir) {
  const { x, y } = from;
  if (dir === 'left') {
    for (let xx = x - 1; xx >= 0; xx--) {
      const hit = islandsByCoord.get(`${xx},${y}`);
      if (hit) return hit;
    }
  }
  if (dir === 'right') {
    for (let xx = x + 1; xx <= 100; xx++) {
      const hit = islandsByCoord.get(`${xx},${y}`);
      if (hit) return hit;
    }
  }
  if (dir === 'up') {
    for (let yy = y - 1; yy >= 0; yy--) {
      const hit = islandsByCoord.get(`${x},${yy}`);
      if (hit) return hit;
    }
  }
  if (dir === 'down') {
    for (let yy = y + 1; yy <= 100; yy++) {
      const hit = islandsByCoord.get(`${x},${yy}`);
      if (hit) return hit;
    }
  }
  return null;
}

export function areAdjacent(islands, from, to) {
  if (!from || !to) return false;
  if (from.x !== to.x && from.y !== to.y) return false;
  if (from.x === to.x && from.y === to.y) return false;

  const byCoord = new Map(islands.map(i => [`${i.x},${i.y}`, i]));
  if (from.x === to.x) {
    const step = Math.sign(to.y - from.y);
    for (let yy = from.y + step; yy !== to.y; yy += step) {
      if (byCoord.has(`${from.x},${yy}`)) return false;
    }
    return true;
  }
  const step = Math.sign(to.x - from.x);
  for (let xx = from.x + step; xx !== to.x; xx += step) {
    if (byCoord.has(`${xx},${from.y}`)) return false;
  }
  return true;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  // delta: +1 to increase, -1 to decrease
  if (!areAdjacent(islands, from, to)) {
    return { valid: false, error: ERR_NON_ADJ };
  }

  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) || 0;
  const next = current + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERR_MAX2 };

  // island counts must not exceed value
  const counts = computeCurrentCounts(islands, bridges);
  const byCoord = new Map(islands.map(i => [`${i.x},${i.y}`, i]));
  const i1 = byCoord.get(`${from.x},${from.y}`);
  const i2 = byCoord.get(`${to.x},${to.y}`);
  const after1 = (counts.get(i1.id) || 0) + delta;
  const after2 = (counts.get(i2.id) || 0) + delta;

  if (after1 > i1.value || after2 > i2.value) {
    return { valid: false, error: ERR_EXCEED };
  }

  // crossing check (only relevant when adding)
  if (delta > 0) {
    const candidateSeg = {
      from: { x: Math.min(from.x, to.x), y: Math.min(from.y, to.y) },
      to: { x: Math.max(from.x, to.x), y: Math.max(from.y, to.y) },
      key,
    };
    if (crossesAny(bridges, candidateSeg, null)) {
      return { valid: false, error: ERR_CROSS };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;
  const byCoord = new Map(islands.map(i => [`${i.x},${i.y}`, i]));
  const adj = new Map(islands.map(i => [i.id, new Set()]));

  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).add(b.id);
    adj.get(b.id).add(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        stack.push(nxt);
      }
    }
  }
  return seen.size === islands.length;
}

export function hasAnyCrossing(bridges) {
  const segs = getSegments(null, bridges);
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      if (segmentsCross(segs[i], segs[j])) return true;
    }
  }
  return false;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) || 0) !== isl.value) return false;
  }
  if (hasAnyCrossing(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}

export function nextIslandByArrow(islands, currentIsland, key) {
  const byCoord = new Map(islands.map(i => [`${i.x},${i.y}`, i]));
  const dir =
    key === 'ArrowLeft' ? 'left' :
    key === 'ArrowRight' ? 'right' :
    key === 'ArrowUp' ? 'up' :
    key === 'ArrowDown' ? 'down' : null;
  if (!dir) return null;
  return nearestIslandInDirection(byCoord, currentIsland, dir);
}

export const ERROR_STRINGS = {
  ERR_NON_ADJ,
  ERR_MAX2,
  ERR_EXCEED,
  ERR_CROSS,
};
EOF
